import { HttpClient } from "../client";
import type { JoinOptions, JoinResult } from "../types";

const DEFAULT_SOURCE = "landing-page";

function getSourceFromUrl(): string | null {
  if (typeof window === "undefined") return null;
  const params = new URLSearchParams(window.location.search);
  return params.get("source") || params.get("s") || null;
}

export class SubscribersResource {
  private client: HttpClient;
  private apiKey: string;
  private projectSlug: string;
  private defaultSource: string;

  constructor(
    client: HttpClient,
    apiKey: string,
    projectSlug: string,
    defaultSource?: string,
  ) {
    this.client = client;
    this.apiKey = apiKey;
    this.projectSlug = projectSlug;
    this.defaultSource = defaultSource ?? DEFAULT_SOURCE;
  }

  private get headers() {
    return { Authorization: `Bearer ${this.apiKey}` };
  }

  async create(options: JoinOptions): Promise<JoinResult> {
    const data = await this.client.request<{ email: string }>(
      "POST",
      `/v1/waitlist/${this.projectSlug}/join`,
      {
        headers: this.headers,
        body: {
          ...options,
          source: options.source ?? getSourceFromUrl() ?? this.defaultSource,
        },
      },
    );

    return {
      message: "Thank you for joining the waitlist!",
      email: data.email,
    };
  }

  async count(projectSlug?: string): Promise<number> {
    const slug = projectSlug ?? this.projectSlug;
    const data = await this.client.request<{ count: number }>(
      "GET",
      `/v1/waitlist/${slug}/count`,
      { headers: this.headers },
    );

    return data.count;
  }
}
