import type { ErrorResponse } from "./types";

export class WaitKitError extends Error {
  constructor(
    message: string,
    public statusCode?: number,
    public issues?: Array<{ path: string; message: string }>,
  ) {
    super(message);
    this.name = "WaitKitError";
  }

  static fromResponse(res: ErrorResponse): WaitKitError {
    return new WaitKitError(res.message, res.statusCode, res.issues);
  }
}
