import { HttpClient } from "./client";
import { SubscribersResource } from "./resources/subscribers";
import type { WaitKitConfig } from "./types";

export const DEFAULT_BASE_URL = "https://api.waitkit.dev";

export class WaitKit {
  subscribers: SubscribersResource;
  private client: HttpClient;
  private apiKey: string;
  private projectSlug: string;

  constructor(config: WaitKitConfig) {
    this.apiKey = config.apiKey;
    this.projectSlug = config.projectSlug;
    this.client = new HttpClient(config.baseUrl ?? DEFAULT_BASE_URL);
    this.subscribers = new SubscribersResource(
      this.client,
      this.apiKey,
      this.projectSlug,
      config.source,
    );
  }
}
